<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> file_appender </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;"> rolling</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">daily</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">log_dir</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;agent.log&quot;</span><span style="color:#9399B2;">);</span></span>
