<span class="line"><span style="color:#9399B2;">        (</span><span style="color:#A6E3A1;">r&quot;Bearer [a-zA-Z0-9._-]+&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;Bearer ***REDACTED***&quot;</span><span style="color:#9399B2;">),</span></span>
